   183→	private readonly _diagnosticCodesMap = new Map<number, number>();
   184→	private readonly _diagnosticSnapshotsMap = new ResourceMap<readonly vscode.Diagnostic[]>(uri => uri.toString(), { onCaseInsensitiveFileSystem: false });
