public listen(): void {
	if (this.listening) {
		return;
	}
	this.listening = true;
	vscode.workspace.onDidOpenTextDocument(this.openTextDocument, this, this._disposables);
	vscode.workspace.onDidCloseTextDocument(this.onDidCloseTextDocument, this, this._disposables);
	vscode.workspace.onDidChangeTextDocument(this.onDidChangeTextDocument, this, this._disposables);
	vscode.window.onDidChangeVisibleTextEditors(e => {
		for (const { document } of e) {
			const syncedBuffer = this.syncedBuffers.get(document.uri);
			if (syncedBuffer) {
				this.requestDiagnostic(syncedBuffer);
			}
		}
	}, this, this._disposables);
	vscode.workspace.textDocuments.forEach(this.openTextDocument, this);

	// Watch for TypeScript/JavaScript file changes on disk (e.g., from git branch switch).
	// When files change outside of VS Code, refresh diagnostics so stale errors are cleared.
	const fileWatcher = this._register(vscode.workspace.createFileSystemWatcher('**/*.{ts,tsx,js,jsx,mts,cts,mjs,cjs}'));
	this._register(fileWatcher.onDidChange(resource => {
		// Only trigger for files not currently open in an editor (those are handled by onDidChangeTextDocument)
		if (!this.syncedBuffers.has(resource)) {
			this.requestAllDiagnostics();
		}
	}));
	this._register(fileWatcher.onDidCreate(_resource => {
		// A new file was created on disk (e.g., git branch switch introduced a new file).
		// Re-request diagnostics so newly visible files are analyzed.
		this.requestAllDiagnostics();
	}));
	this._register(fileWatcher.onDidDelete(resource => {
		// File was deleted from disk; remove it from pending diagnostics.
		this.pendingDiagnostics.delete(resource);
		this.pendingGetErr?.files.delete(resource);
	}));
}

